CREATE TABLE J09C_temp AS
SELECT * FROM decision_table
WHERE TOUR LIKE 'J09C%';

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09C_temp
        GROUP BY HAUS
    )
    WHERE eq_count < 3
);

UPDATE J09C_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09C_temp
        GROUP BY HAUS
    )
    WHERE eq_count >= 3
);
